1	import { useState, useCallback, useRef, useEffect } from "react";
2	import { useQuery, useQueryClient } from "@tanstack/react-query";
3	import { fetchGapAnalysis } from "../services/api";
4	import { runSSEFetch, type SSECallbacks } from "./useSSE";
5	import type { GapAnalysis, SSEProgressEvent, SSEErrorEvent } from "shared";
6	
7	const BASE_URL = "/api";
8	
9	/**
10	 * Hook to fetch existing gap analysis for a project.
11	 */
12	export function useGapAnalysis(projectId: string | null) {
13	  return useQuery({
14	    queryKey: ["gapAnalysis", projectId],
15	    queryFn: () => fetchGapAnalysis(projectId!),
16	    enabled: !!projectId,
17	  });
18	}
19	
20	export interface RunAnalysisCallbacks extends SSECallbacks<GapAnalysis> {
21	  onProgress?: (event: SSEProgressEvent) => void;
22	  onComplete?: (data: GapAnalysis) => void;
23	  onError?: (error: SSEErrorEvent) => void;
24	}
25	
26	export interface UseRunAnalysisResult {
27	  runAnalysis: (projectId: string, callbacks?: RunAnalysisCallbacks) => void;
28	  cancel: () => void;
29	  isRunning: boolean;
30	  progress: SSEProgressEvent[];
31	  result: GapAnalysis | null;
32	  error: SSEErrorEvent | null;
33	}
34	
35	/**
36	 * Hook to run gap analysis with SSE streaming progress.
37	 *
38	 * This hook manages the state of a streaming analysis request,
39	 * providing progress updates, results, and error handling.
40	 *
41	 * @example
42	 * ```tsx
43	 * const { runAnalysis, isRunning, progress, result, error } = useRunAnalysis();
44	 *
45	 * const handleClick = () => {
46	 *   runAnalysis(projectId, {
47	 *     onProgress: (event) => console.log("Progress:", event.step),
48	 *     onComplete: (data) => console.log("Done!", data),
49	 *     onError: (err) => console.error("Error:", err.message),
50	 *   });
51	 * };
52	 * ```
53	 */
54	export function useRunAnalysis(): UseRunAnalysisResult {
55	  const queryClient = useQueryClient();
56	  const [isRunning, setIsRunning] = useState(false);
57	  const [progress, setProgress] = useState<SSEProgressEvent[]>([]);
58	  const [result, setResult] = useState<GapAnalysis | null>(null);
59	  const [error, setError] = useState<SSEErrorEvent | null>(null);
60	
61	  const abortControllerRef = useRef<AbortController | null>(null);
62	  const callbacksRef = useRef<RunAnalysisCallbacks | undefined>(undefined);
63	
64	  const cancel = useCallback(() => {
65	    if (abortControllerRef.current) {
66	      abortControllerRef.current.abort();
67	      abortControllerRef.current = null;
68	    }
69	    setIsRunning(false);
70	  }, []);
71	
72	  const runAnalysis = useCallback(
73	    (projectId: string, callbacks?: RunAnalysisCallbacks) => {
74	      // Cancel any existing request
75	      cancel();
76	
77	      // Store callbacks for access in handlers
78	      callbacksRef.current = callbacks;
79	
80	      // Reset state
81	      setProgress([]);
82	      setResult(null);
83	      setError(null);
84	      setIsRunning(true);
85	
86	      // Create new abort controller
87	      const abortController = new AbortController();
88	      abortControllerRef.current = abortController;
89	
90	      const url = `${BASE_URL}/projects/${projectId}/analysis`;
91	
92	      runSSEFetch<GapAnalysis>(url, {
93	        method: "POST",
94	        signal: abortController.signal,
95	        onProgress: (event) => {
96	          setProgress((prev) => {
97	            const next = [...prev, event];
98	            // Keep last 20 events to prevent memory bloat
99	            return next.length > 20 ? next.slice(-20) : next;
100	          });
101	          callbacksRef.current?.onProgress?.(event);
102	        },
103	        onComplete: (data) => {
104	          setResult(data);
105	          setIsRunning(false);
106	          // Invalidate queries to refresh data
107	          queryClient.invalidateQueries({ queryKey: ["gapAnalysis", projectId] });
108	          callbacksRef.current?.onComplete?.(data);
109	        },
110	        onError: (err) => {
111	          setError(err);
112	          setIsRunning(false);
113	          callbacksRef.current?.onError?.(err);
114	        },
115	      }).catch((err) => {
116	        if (!abortControllerRef.current?.signal.aborted) {
117	          setError({
118	            type: "error",
119	            code: "FETCH_ERROR",
120	            message: err instanceof Error ? err.message : "Unknown error",
121	          });
122	          setIsRunning(false);
123	        }
124	      });
125	    },
126	    [cancel, queryClient]
127	  );
128	
129	  // Cleanup on unmount
130	  useEffect(() => {
131	    return () => {
132	      if (abortControllerRef.current) {
133	        abortControllerRef.current.abort();
134	      }
135	    };
136	  }, []);
137	
138	  return {
139	    runAnalysis,
140	    cancel,
141	    isRunning,
142	    progress,
143	    result,
144	    error,
145	  };
146	}
147	
148	/**
149	 * Standalone function to run analysis with SSE streaming.
150	 * Returns a cancel function.
151	 *
152	 * Use this when you need more control over the analysis lifecycle
153	 * or when using outside of React components.
154	 *
155	 * @example
156	 * ```ts
157	 * const cancel = await runAnalysisWithSSE(
158	 *   projectId,
159	 *   (event) => console.log("Progress:", event.step),
160	 *   (data) => console.log("Complete:", data),
161	 *   (error) => console.error("Error:", error.message)
162	 * );
163	 *
164	 * // Later, to cancel:
165	 * cancel();
166	 * ```
167	 */
168	export function runAnalysisWithSSE(
169	  projectId: string,
170	  onProgress: (event: SSEProgressEvent) => void,
171	  onComplete: (data: GapAnalysis) => void,
172	  onError: (error: SSEErrorEvent) => void
173	): () => void {
174	  const abortController = new AbortController();
175	
176	  const url = `${BASE_URL}/projects/${projectId}/analysis`;
177	
178	  runSSEFetch<GapAnalysis>(url, {
179	    method: "POST",
180	    signal: abortController.signal,
181	    onProgress,
182	    onComplete,
183	    onError,
184	  }).catch((err) => {
185	    if (!abortController.signal.aborted) {
186	      onError({
187	        type: "error",
188	        code: "FETCH_ERROR",
189	        message: err instanceof Error ? err.message : "Unknown error",
190	      });
191	    }
192	  });
193	
194	  // Return cancel function
195	  return () => abortController.abort();
196	}
