1	import { Router, Request, Response } from "express";
2	import { v4 as uuid } from "uuid";
3	import db, { now } from "../db/index.js";
4	import { fetchBrandReport, fetchDomainReport, fetchUrlReport, fetchChats, fetchChatContent, fetchSearchQueries } from "../services/peec.js";
5	import { synthesizeGapAnalysis, type PeecData, type GapAnalysisResult } from "../services/claude.js";
6	import type { BrandBrief, GapAnalysis, ContentStrategy, SSEProgressEvent, SSECompleteEvent, SSEErrorEvent } from "shared";
7	
8	const router = Router();
9	
10	// Helper to send SSE events
11	function sendSSE<T = GapAnalysis>(res: Response, event: SSEProgressEvent | SSECompleteEvent<T> | SSEErrorEvent): void {
12	  res.write(`data: ${JSON.stringify(event)}\n\n`);
13	}
14	
15	// Helper to set SSE headers
16	function setSSEHeaders(res: Response): void {
17	  res.setHeader("Content-Type", "text/event-stream");
18	  res.setHeader("Cache-Control", "no-cache");
19	  res.setHeader("Connection", "keep-alive");
20	}
21	
22	// Helper to get brand brief by project ID
23	function getBrandBrief(projectId: string): BrandBrief | null {
24	  const row = db
25	    .prepare(
26	      `SELECT id, project_id, brand_name, domain, category, desired_tone,
27	              desired_claims, key_differentiators, competitors, created_at, updated_at
28	       FROM brand_briefs
29	       WHERE project_id = ?`
30	    )
31	    .get(projectId) as Record<string, unknown> | undefined;
32	
33	  if (!row) {
34	    return null;
35	  }
36	
37	  try {
38	    return {
39	      id: row.id as string,
40	      projectId: row.project_id as string,
41	      brandName: row.brand_name as string,
42	      domain: row.domain as string,
43	      category: row.category as string,
44	      desiredTone: row.desired_tone as BrandBrief["desiredTone"],
45	      desiredClaims: JSON.parse(row.desired_claims as string),
46	      keyDifferentiators: JSON.parse(row.key_differentiators as string),
47	      competitors: JSON.parse(row.competitors as string),
48	      createdAt: row.created_at as string,
49	      updatedAt: row.updated_at as string,
50	    };
51	  } catch (error) {
52	    const errorMessage = error instanceof Error ? error.message : "Invalid JSON in brand brief";
53	    throw new Error(`Failed to parse brand brief: ${errorMessage}`);
54	  }
55	}
56	
57	// Helper to convert DB row to GapAnalysis
58	function rowToGapAnalysis(row: Record<string, unknown>): GapAnalysis {
59	  try {
60	    const analysis = JSON.parse(row.analysis as string) as GapAnalysisResult;
61	    return {
62	      id: row.id as string,
63	      projectId: row.project_id as string,
64	      currentStateSummary: analysis.currentStateSummary,
65	      targetState: analysis.targetState,
66	      gaps: analysis.gaps,
67	      citationSources: analysis.citationSources,
68	      createdAt: row.created_at as string,
69	    };
70	  } catch (error) {
71	    const errorMessage = error instanceof Error ? error.message : "Invalid JSON in gap analysis";
72	    throw new Error(`Failed to parse gap analysis: ${errorMessage}`);
73	  }
