28	function parseSSEEvents(chunk: string): Array<SSEProgressEvent | SSECompleteEvent<unknown> | SSEErrorEvent> {
29	  const events: Array<SSEProgressEvent | SSECompleteEvent<unknown> | SSEErrorEvent> = [];
