50	/**
51	 * Run a fetch request with SSE streaming.
52	 * Returns a cancel function.
53	 */
54	export async function runSSEFetch<T>(
55	  url: string,
56	  options: {
57	    method?: "GET" | "POST";
58	    body?: unknown;
59	    onProgress?: (event: SSEProgressEvent) => void;
60	    onComplete?: (data: T) => void;
61	    onError?: (error: SSEErrorEvent) => void;
62	    signal?: AbortSignal;
63	  }
64	): Promise<void> {
65	  const { method = "POST", body, onProgress, onComplete, onError, signal } = options;
66	
67	  try {
68	    const fetchOptions: RequestInit = {
69	      method,
70	      headers: {
71	        Accept: "text/event-stream",
72	        "Content-Type": "application/json",
73	      },
74	      signal,
75	    };
76	
77	    if (body && method !== "GET") {
78	      fetchOptions.body = JSON.stringify(body);
79	    }
80	
81	    const response = await fetch(url, fetchOptions);
82	
83	    if (!response.ok) {
84	      const errorData = await response.json().catch(() => ({
85	        error: "Request failed",
86	        code: "UNKNOWN",
87	      }));
88	      onError?.({
89	        type: "error",
90	        code: errorData.code || "HTTP_ERROR",
91	        message: errorData.error || `HTTP ${response.status}`,
92	      });
93	      return;
94	    }
95	
96	    if (!response.body) {
97	      onError?.({
98	        type: "error",
99	        code: "NO_BODY",
100	        message: "Response has no body",
101	      });
102	      return;
103	    }
104	
105	    const reader = response.body.getReader();
106	    const decoder = new TextDecoder();
107	    let buffer = "";
108	
109	    while (true) {
110	      const { done, value } = await reader.read();
111	
112	      if (done) {
113	        break;
114	      }
115	
116	      // Decode the chunk and add to buffer
117	      buffer += decoder.decode(value, { stream: true });
118	
119	      // Process complete events (separated by double newlines)
120	      const parts = buffer.split("\n\n");
121	      buffer = parts.pop() || ""; // Keep incomplete part in buffer
122	
123	      for (const part of parts) {
124	        const events = parseSSEEvents(part);
125	        for (const event of events) {
126	          if (event.type === "progress") {
127	            onProgress?.(event);
128	          } else if (event.type === "complete") {
129	            onComplete?.((event as SSECompleteEvent<T>).data);
130	          } else if (event.type === "error") {
131	            onError?.(event);
132	          }
133	        }
134	      }
135	    }
136	
137	    // Process any remaining buffer
138	    if (buffer.trim()) {
139	      const events = parseSSEEvents(buffer);
140	      for (const event of events) {
141	        if (event.type === "progress") {
142	          onProgress?.(event);
143	        } else if (event.type === "complete") {
144	          onComplete?.((event as SSECompleteEvent<T>).data);
145	        } else if (event.type === "error") {
146	          onError?.(event);
147	        }
148	      }
149	    }
150	  } catch (err) {
151	    if (err instanceof Error && err.name === "AbortError") {
152	      // Request was cancelled, don't call onError
153	      return;
154	    }
155	    onError?.({
156	      type: "error",
157	      code: "FETCH_ERROR",
158	      message: err instanceof Error ? err.message : "Unknown error",
159	    });
160	  }
161	}
162	
163	/**
164	 * React hook for SSE-based streaming requests.
165	 */
166	export function useSSE<T>(url: string, options?: UseSSEOptions<T>): UseSSEResult<T> {
167	  const [isRunning, setIsRunning] = useState(false);
168	  const [progress, setProgress] = useState<SSEProgressEvent[]>([]);
169	  const [result, setResult] = useState<T | null>(null);
170	  const [error, setError] = useState<SSEErrorEvent | null>(null);
171	
172	  const abortControllerRef = useRef<AbortController | null>(null);
173	
174	  // Create a stable key for options to avoid unnecessary re-renders
175	  const optionsKey = JSON.stringify({
176	    method: options?.method,
177	    body: options?.body,
178	  });
179	
180	  const cancel = useCallback(() => {
181	    if (abortControllerRef.current) {
182	      abortControllerRef.current.abort();
183	      abortControllerRef.current = null;
184	    }
185	    setIsRunning(false);
186	  }, []);
187	
188	  const start = useCallback(() => {
189	    // Cancel any existing request
190	    cancel();
191	
192	    // Reset state
193	    setProgress([]);
194	    setResult(null);
195	    setError(null);
196	    setIsRunning(true);
197	
198	    // Create new abort controller
199	    const abortController = new AbortController();
200	    abortControllerRef.current = abortController;
201	
202	    runSSEFetch<T>(url, {
203	      method: options?.method,
204	      body: options?.body,
205	      signal: abortController.signal,
206	      onProgress: (event) => {
207	        setProgress((prev) => {
208	          const next = [...prev, event];
209	          // Keep last 50 events to prevent memory bloat
210	          return next.length > 50 ? next.slice(-50) : next;
211	        });
212	        options?.onProgress?.(event);
213	      },
214	      onComplete: (data) => {
215	        setResult(data);
216	        setIsRunning(false);
217	        options?.onComplete?.(data);
218	      },
219	      onError: (err) => {
220	        setError(err);
221	        setIsRunning(false);
222	        options?.onError?.(err);
223	      },
224	    }).catch((err) => {
225	      if (!abortControllerRef.current?.signal.aborted) {
226	        setError({
227	          type: "error",
228	          code: "FETCH_ERROR",
229	          message: err instanceof Error ? err.message : "Unknown error",
230	        });
231	        setIsRunning(false);
232	      }
233	    });
234	  }, [url, optionsKey, cancel]);
235	
236	  // Cleanup on unmount
237	  useEffect(() => {
238	    return () => {
239	      if (abortControllerRef.current) {
240	        abortControllerRef.current.abort();
241	      }
242	    };
243	  }, []);
244	
245	  return {
246	    start,
247	    cancel,
248	    isRunning,
249	    progress,
250	    result,
251	    error,
252	  };
253	}
